# @cctt_verify {"v":2,"sym":"sympy.solvers.tests.test_solveset.test_piecewise_solveset","kind":"function","src_hash":"8f1d71dd889bb3e0","in":{"base":"Any"},"out":{"base":"Any","pred":"set(solveset_real(eq, x)) == set(FiniteSet(-1, 5)) and solveset_real(absxm3 - y, x) == FiniteSet(-y + 3, y + 3) and solveset(Piecewise((x - 1, Ne(x, I)), (x, True)), x) == FiniteSet(1) and solveset(g > 0, x, S.Reals) == Interval.open(10, oo) and solveset(f, x, domain=Interval(-3, 10)) == Interval(-3, 10) and solveset(f, x, domain=S.Reals) == FiniteSet(0) and solveset(g) == FiniteSet(pi)"},"spec":{"lhs":"test_piecewise_solveset()","rhs":"test_piecewise_solveset produces the expected output","over":{"base":"Any"},"name":"test_piecewise_solveset_correct"},"guarantee":"test_piecewise_solveset produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.solvers.tests.test_solveset.test_piecewise_solveset_correct","statement":"Path(test_piecewise_solveset(x), test_piecewise_solveset produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"92f69bc448fdff75"}
def test_piecewise_solveset():
    eq = Piecewise((x - 2, Gt(x, 2)), (2 - x, True)) - 3
    assert set(solveset_real(eq, x)) == set(FiniteSet(-1, 5))

    absxm3 = Piecewise(
        (x - 3, 0 <= x - 3),
        (3 - x, 0 > x - 3))
    y = Symbol('y', positive=True)
    assert solveset_real(absxm3 - y, x) == FiniteSet(-y + 3, y + 3)

    f = Piecewise(((x - 2)**2, x >= 0), (0, True))
    assert solveset(f, x, domain=S.Reals) == Union(FiniteSet(2), Interval(-oo, 0, True, True))

    assert solveset(
        Piecewise((x + 1, x > 0), (I, True)) - I, x, S.Reals
        ) == Interval(-oo, 0)

    assert solveset(Piecewise((x - 1, Ne(x, I)), (x, True)), x) == FiniteSet(1)

    # issue 19718
    g = Piecewise((1, x > 10), (0, True))
    assert solveset(g > 0, x, S.Reals) == Interval.open(10, oo)

    from sympy.logic.boolalg import BooleanTrue
    f = BooleanTrue()
    assert solveset(f, x, domain=Interval(-3, 10)) == Interval(-3, 10)

    # issue 20552
    f = Piecewise((0, Eq(x, 0)), (x**2/Abs(x), True))
    g = Piecewise((0, Eq(x, pi)), ((x - pi)/sin(x), True))
    assert solveset(f, x, domain=S.Reals) == FiniteSet(0)
    assert solveset(g) == FiniteSet(pi)


