# @cctt_verify {"v":2,"sym":"sympy.solvers.tests.test_solveset.test_solvify_piecewise","kind":"function","src_hash":"2dfbf7c2f7bc7ee3","in":{"base":"Any"},"out":{"base":"Any","pred":"solvify(p1, x, S.Reals) == [0] and solvify(p2, x, S.Reals) == [-6, 1] and solvify(p3, x, S.Reals) == [0] and solvify(p4, x, S.Reals) == [pi]"},"spec":{"lhs":"test_solvify_piecewise()","rhs":"test_solvify_piecewise produces the expected output","over":{"base":"Any"},"name":"test_solvify_piecewise_correct"},"guarantee":"test_solvify_piecewise produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.solvers.tests.test_solveset.test_solvify_piecewise_correct","statement":"Path(test_solvify_piecewise(x), test_solvify_piecewise produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"e52583d261ff6494"}
def test_solvify_piecewise():
    p1 = Piecewise((0, x < -1), (x**2, x <= 1), (log(x), True))
    p2 = Piecewise((0, x < -10), (x**2 + 5*x - 6, x >= -9))
    p3 = Piecewise((0, Eq(x, 0)), (x**2/Abs(x), True))
    p4 = Piecewise((0, Eq(x, pi)), ((x - pi)/sin(x), True))

    # issue 21079
    assert solvify(p1, x, S.Reals) == [0]
    assert solvify(p2, x, S.Reals) == [-6, 1]
    assert solvify(p3, x, S.Reals) == [0]
    assert solvify(p4, x, S.Reals) == [pi]


