# @cctt_verify {"v":2,"sym":"sympy.solvers.tests.test_solveset.test_nonlinsolve_using_substitution","kind":"function","src_hash":"9bae89a3b9e5c306","in":{"base":"Any"},"out":{"base":"Any","pred":"nonlinsolve(system, [x, y]) == FiniteSet(soln) and nonlinsolve(system, syms) == soln"},"spec":{"lhs":"test_nonlinsolve_using_substitution()","rhs":"test_nonlinsolve_using_substitution produces the expected output","over":{"base":"Any"},"name":"test_nonlinsolve_using_substitution_correct"},"guarantee":"test_nonlinsolve_using_substitution produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.solvers.tests.test_solveset.test_nonlinsolve_using_substitution_correct","statement":"Path(test_nonlinsolve_using_substitution(x), test_nonlinsolve_using_substitution produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"0f4d95b8e89fa711"}
def test_nonlinsolve_using_substitution():
    x, y, z, n = symbols('x, y, z, n', real = True)
    system = [(x + y)*n - y**2 + 2]
    s_x = (n*y - y**2 + 2)/n
    soln = (-s_x, y)
    assert nonlinsolve(system, [x, y]) == FiniteSet(soln)

    system = [z**2*x**2 - z**2*y**2/exp(x)]
    soln_real_1 = (y, x, 0)
    soln_real_2 = (-exp(x/2)*Abs(x), x, z)
    soln_real_3 = (exp(x/2)*Abs(x), x, z)
    soln_complex_1 = (-x*exp(x/2), x, z)
    soln_complex_2 = (x*exp(x/2), x, z)
    syms = [y, x, z]
    soln = FiniteSet(soln_real_1, soln_complex_1, soln_complex_2,\
        soln_real_2, soln_real_3)
    assert nonlinsolve(system,syms) == soln


