# @cctt_verify {"v":2,"sym":"sympy.solvers.tests.test_solveset.test_issue_13961","kind":"function","src_hash":"10bf7b2808dfa748","in":{"base":"Any"},"out":{"base":"Any","pred":"nonlinsolve(S, *V) == sol"},"spec":{"lhs":"test_issue_13961()","rhs":"test_issue_13961 produces the expected output","over":{"base":"Any"},"name":"test_issue_13961_correct"},"guarantee":"test_issue_13961 produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.solvers.tests.test_solveset.test_issue_13961_correct","statement":"Path(test_issue_13961(x), test_issue_13961 produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"687a01f6b641d5e9"}
def test_issue_13961():
    V = (ax, bx, cx, gx, jx, lx, mx, nx, q) = symbols('ax bx cx gx jx lx mx nx q')
    S = (ax*q - lx*q - mx, ax - gx*q - lx, bx*q**2 + cx*q - jx*q - nx, q*(-ax*q + lx*q + mx), q*(-ax + gx*q + lx))

    sol = FiniteSet((lx + mx/q, (-cx*q + jx*q + nx)/q**2, cx, mx/q**2, jx, lx, mx, nx, Complement({q}, {0})),
                    (lx + mx/q, (cx*q - jx*q - nx)/q**2*-1, cx, mx/q**2, jx, lx, mx, nx, Complement({q}, {0})))
    assert nonlinsolve(S, *V) == sol
    # The two solutions are in fact identical, so even better if only one is returned


