# @cctt_verify {"v":2,"sym":"sympy.solvers.tests.test_solveset.test_issue_2777","kind":"function","src_hash":"4d3a1607dab56c7b","in":{"base":"Any"},"out":{"base":"Any","pred":"nonlinsolve((e1, e2), (x, y)) == ans and nonlinsolve((e1, e2 / (x - a)), (x, y)) == S.EmptySet and nonlinsolve((e1, e2), (x, y)) == S.EmptySet"},"spec":{"lhs":"test_issue_2777()","rhs":"test_issue_2777 produces the expected output","over":{"base":"Any"},"name":"test_issue_2777_correct"},"guarantee":"test_issue_2777 produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.solvers.tests.test_solveset.test_issue_2777_correct","statement":"Path(test_issue_2777(x), test_issue_2777 produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"de850e6f26606985"}
def test_issue_2777():
    # the equations represent two circles
    x, y = symbols('x y', real=True)
    e1, e2 = sqrt(x**2 + y**2) - 10, sqrt(y**2 + (-x + 10)**2) - 3
    a, b = Rational(191, 20), 3*sqrt(391)/20
    ans = {(a, -b), (a, b)}
    assert nonlinsolve((e1, e2), (x, y)) == ans
    assert nonlinsolve((e1, e2/(x - a)), (x, y)) == S.EmptySet
    # make the 2nd circle's radius be -3
    e2 += 6
    assert nonlinsolve((e1, e2), (x, y)) == S.EmptySet


