# @cctt_verify {"v":2,"sym":"sympy.solvers.tests.test_solveset.test_issue_8828","kind":"function","src_hash":"024887300bd0a874","in":{"base":"Any"},"out":{"base":"Any","pred":"A == B"},"spec":{"lhs":"test_issue_8828()","rhs":"test_issue_8828 produces the expected output","over":{"base":"Any"},"name":"test_issue_8828_correct"},"guarantee":"test_issue_8828 produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.solvers.tests.test_solveset.test_issue_8828_correct","statement":"Path(test_issue_8828(x), test_issue_8828 produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"25d9390144c71770"}
def test_issue_8828():
    x1 = 0
    y1 = -620
    r1 = 920
    x2 = 126
    y2 = 276
    x3 = 51
    y3 = 205
    r3 = 104
    v = [x, y, z]

    f1 = (x - x1)**2 + (y - y1)**2 - (r1 - z)**2
    f2 = (x2 - x)**2 + (y2 - y)**2 - z**2
    f3 = (x - x3)**2 + (y - y3)**2 - (r3 - z)**2
    F = [f1, f2, f3]

    g1 = sqrt((x - x1)**2 + (y - y1)**2) + z - r1
    g2 = f2
    g3 = sqrt((x - x3)**2 + (y - y3)**2) + z - r3
    G = [g1, g2, g3]

    # both soln same
    A = nonlinsolve(F, v)
    B = nonlinsolve(G, v)
    assert A == B


