# @cctt_verify {"v":2,"sym":"sympy.solvers.tests.test_solveset.test_nonlinsolve_conditionset","kind":"function","src_hash":"31c8b391bdeb015c","in":{"base":"Any"},"out":{"base":"Any","pred":"nonlinsolve([f1, f2], [x, y]) == soln"},"spec":{"lhs":"test_nonlinsolve_conditionset()","rhs":"test_nonlinsolve_conditionset produces the expected output","over":{"base":"Any"},"name":"test_nonlinsolve_conditionset_correct"},"guarantee":"test_nonlinsolve_conditionset produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.solvers.tests.test_solveset.test_nonlinsolve_conditionset_correct","statement":"Path(test_nonlinsolve_conditionset(x), test_nonlinsolve_conditionset produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"fe5b02af57f8605a"}
def test_nonlinsolve_conditionset():
    # when solveset failed to solve all the eq
    # return conditionset
    f = Function('f')
    f1 = f(x) - pi/2
    f2 = f(y) - pi*Rational(3, 2)
    intermediate_system = Eq(2*f(x) - pi, 0) & Eq(2*f(y) - 3*pi, 0)
    syms = Tuple(x, y)
    soln = ConditionSet(
        syms,
        intermediate_system,
        S.Complexes**2)
    assert nonlinsolve([f1, f2], [x, y]) == soln


