# @cctt_verify {"v":2,"sym":"sympy.solvers.tests.test_solveset.test_issue_21022","kind":"function","src_hash":"2e4e34539eee8174","in":{"base":"Any"},"out":{"base":"Any","pred":"len(res) == len(ans) == 4 and res == ans and len(result) == 8"},"spec":{"lhs":"test_issue_21022()","rhs":"test_issue_21022 produces the expected output","over":{"base":"Any"},"name":"test_issue_21022_correct"},"guarantee":"test_issue_21022 produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.solvers.tests.test_solveset.test_issue_21022_correct","statement":"Path(test_issue_21022(x), test_issue_21022 produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"fb1c6bb4ab12eeaa"}
def test_issue_21022():
    from sympy.core.sympify import sympify

    eqs = [
    'k-16',
    'p-8',
    'y*y+z*z-x*x',
    'd - x + p',
    'd*d+k*k-y*y',
    'z*z-p*p-k*k',
    'abc-efg',
    ]
    efg = Symbol('efg')
    eqs = [sympify(x) for x in eqs]

    syb = list(ordered(set.union(*[x.free_symbols for x in eqs])))
    res = nonlinsolve(eqs, syb)

    ans = FiniteSet(
    (efg, 32, efg, 16, 8, 40, -16*sqrt(5), -8*sqrt(5)),
    (efg, 32, efg, 16, 8, 40, -16*sqrt(5), 8*sqrt(5)),
    (efg, 32, efg, 16, 8, 40, 16*sqrt(5), -8*sqrt(5)),
    (efg, 32, efg, 16, 8, 40, 16*sqrt(5), 8*sqrt(5)),
    )
    assert len(res) == len(ans) == 4
    assert res == ans
    for result in res.args:
        assert len(result) == 8


