# @cctt_verify {"v":2,"sym":"sympy.solvers.tests.test_solveset.test_logarithmic","kind":"function","src_hash":"7b31fadfe2e958ff","in":{"base":"Any"},"out":{"base":"Any","pred":"solveset_real(log(x - 3) + log(x + 3), x) == FiniteSet(-sqrt(10), sqrt(10)) and solveset_real(log(x + 1) - log(2 * x - 1), x) == FiniteSet(2) and solveset(log(x ** y) - y * log(x), x, S.Reals) == S.Reals"},"spec":{"lhs":"test_logarithmic()","rhs":"test_logarithmic produces the expected output","over":{"base":"Any"},"name":"test_logarithmic_correct"},"guarantee":"test_logarithmic produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.solvers.tests.test_solveset.test_logarithmic_correct","statement":"Path(test_logarithmic(x), test_logarithmic produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"8e39a728000d8764"}
def test_logarithmic():
    assert solveset_real(log(x - 3) + log(x + 3), x) == FiniteSet(
        -sqrt(10), sqrt(10))
    assert solveset_real(log(x + 1) - log(2*x - 1), x) == FiniteSet(2)
    assert solveset_real(log(x + 3) + log(1 + 3/x) - 3, x) == FiniteSet(
        -3 + sqrt(-12 + exp(3))*exp(Rational(3, 2))/2 + exp(3)/2,
        -sqrt(-12 + exp(3))*exp(Rational(3, 2))/2 - 3 + exp(3)/2)

    eq = z - log(x) + log(y/(x*(-1 + y**2/x**2)))
    assert solveset_real(eq, x) == \
        Intersection(S.Reals, FiniteSet(-sqrt(y**2 - y*exp(z)),
            sqrt(y**2 - y*exp(z)))) - \
        Intersection(S.Reals, FiniteSet(-sqrt(y**2), sqrt(y**2)))
    assert solveset_real(
        log(3*x) - log(-x + 1) - log(4*x + 1), x) == FiniteSet(Rational(-1, 2), S.Half)
    assert solveset(log(x**y) - y*log(x), x, S.Reals) == S.Reals

