# @cctt_verify {"v":2,"sym":"sympy.solvers.tests.test_solveset.test_linear_coeffs","kind":"function","src_hash":"261dad6f627a00f4","in":{"base":"Any"},"out":{"base":"Any","pred":"linear_coeffs(0, x) == [0, 0] and all((i is S.Zero for i in linear_coeffs(0, x))) and linear_coeffs(x + 2 * y + 3, x, y) == [1, 2, 3] and linear_coeffs(x + 2 * y + 3, y, x) == [2, 1, 3] and linear_coeffs(x + 2 * x ** 2 + 3, x, x ** 2) == [1, 2, 3] and linear_coeffs(a * (x + y), x, y) == [a, a, 0] and linear_coeffs(1.0, x, y) == [0, 0, 1.0] and linear_coeffs(Eq(x, x + y), x, y, dict=True) == {y: -1} and linear_coeffs(0, x, y, dict=True) == {}"},"spec":{"lhs":"test_linear_coeffs()","rhs":"test_linear_coeffs produces the expected output","over":{"base":"Any"},"name":"test_linear_coeffs_correct"},"guarantee":"test_linear_coeffs produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.solvers.tests.test_solveset.test_linear_coeffs_correct","statement":"Path(test_linear_coeffs(x), test_linear_coeffs produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"197a183a718a4e20"}
def test_linear_coeffs():
    from sympy.solvers.solveset import linear_coeffs
    assert linear_coeffs(0, x) == [0, 0]
    assert all(i is S.Zero for i in linear_coeffs(0, x))
    assert linear_coeffs(x + 2*y + 3, x, y) == [1, 2, 3]
    assert linear_coeffs(x + 2*y + 3, y, x) == [2, 1, 3]
    assert linear_coeffs(x + 2*x**2 + 3, x, x**2) == [1, 2, 3]
    raises(ValueError, lambda:
        linear_coeffs(x + 2*x**2 + x**3, x, x**2))
    raises(ValueError, lambda:
        linear_coeffs(1/x*(x - 1) + 1/x, x))
    raises(ValueError, lambda:
        linear_coeffs(x, x, x))
    assert linear_coeffs(a*(x + y), x, y) == [a, a, 0]
    assert linear_coeffs(1.0, x, y) == [0, 0, 1.0]
    # don't include coefficients of 0
    assert linear_coeffs(Eq(x, x + y), x, y, dict=True) == {y: -1}
    assert linear_coeffs(0, x, y, dict=True) == {}


