# @cctt_verify {"v":2,"sym":"sympy.solvers.tests.test_solveset.test_issue_26077","kind":"function","src_hash":"a856a52ee7d214b6","in":{"base":"Any"},"out":{"base":"Any","pred":"solution.as_dummy() == critical_points.as_dummy()"},"spec":{"lhs":"test_issue_26077()","rhs":"test_issue_26077 produces the expected output","over":{"base":"Any"},"name":"test_issue_26077_correct"},"guarantee":"test_issue_26077 produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.solvers.tests.test_solveset.test_issue_26077_correct","statement":"Path(test_issue_26077(x), test_issue_26077 produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"3015a56b98f30ce9"}
def test_issue_26077():
    _n = Symbol('_n')
    function = x*cot(5*x)
    critical_points = stationary_points(function, x, S.Reals)
    excluded_points = Union(
        ImageSet(Lambda(_n, 2*_n*pi/5), S.Integers),
        ImageSet(Lambda(_n, 2*_n*pi/5 + pi/5), S.Integers)
    )
    solution = ConditionSet(x,
        Eq(x*(-5*cot(5*x)**2 - 5) + cot(5*x), 0),
        Complement(S.Reals, excluded_points)
    )
    assert solution.as_dummy() == critical_points.as_dummy()
